  font-weight: 500; color: var(--mocha); text-align: right;
  padding: 4px 10px; border-bottom: 1px solid var(--tan); font-size: 10.5px; line-height: 1.25;
}
.scl-table th:first-child, .scl-table td:first-child { text-align: left; }
